const __pageData = JSON.parse('{"title":"Node环境变量设置","description":"","frontmatter":{},"headers":[{"level":2,"title":"在Webpack配置文件直接赋值（不推荐）","slug":"在webpack配置文件直接赋值-不推荐","link":"#在webpack配置文件直接赋值-不推荐","children":[]},{"level":2,"title":"命令行（CLI）设置（不推荐）","slug":"命令行-cli-设置-不推荐","link":"#命令行-cli-设置-不推荐","children":[{"level":3,"title":"Windows 系统","slug":"windows-系统","link":"#windows-系统","children":[]}]},{"level":2,"title":"配置 package.json（不推荐）","slug":"配置-package-json-不推荐","link":"#配置-package-json-不推荐","children":[{"level":3,"title":"windows 系统","slug":"windows-系统-1","link":"#windows-系统-1","children":[]}]},{"level":2,"title":"cross-env跨平台（推荐）","slug":"cross-env跨平台-推荐","link":"#cross-env跨平台-推荐","children":[]}],"relativePath":"notes/2.basic/5.node/4.环境变量设置.md","lastUpdated":1675675679000}');
